Here's a minimal Flask endpoint to extract a ZIP uploaded by the user to an application data directory:

```python
from flask import Flask, request, send_from_directory, os
import zipfile

app = Flask(__name__)
DATA_DIR = os.path.join(os.getcwd(), 'app_data')  # change as needed
os.makedirs(DATA_DIR, exist_ok=True)

@app.route("/extract", methods=["POST"])
def extract_zip():
    if 'file' not in request.files:
        return "No file provided", 400
    file = request.files['file']
    if not file.filename or not file.mimetype == 'application/zip':
        return "Invalid or empty ZIP file", 400

    extract_to = os.path.join(DATA_DIR, file.filename.split('.');

    try:
        with zipfile.ZipFile(file.stream, 'r') as zip_ref:
            zip_ref.extractall(extract_to)
        return f"Extracted to {extract_to}", 200
    except Exception as e:
        return f"Error: {str(e)}", 500

if __name__ == "__main__":
    app.run()
